import React, { createContext, useState, useContext, useEffect } from 'react';

const DataContext = createContext(null);

// Hàm hỗ trợ lấy dữ liệu từ LocalStorage hoặc dùng giá trị mặc định
const getInitialData = (key, defaultValue) => {
  const saved = localStorage.getItem(key);
  if (saved) {
    return JSON.parse(saved);
  }
  return defaultValue;
};

export const DataProvider = ({ children }) => {
  // 1. DANH SÁCH CA LÀM VIỆC (MỚI)
  // Mặc định khởi tạo 1 ca hành chính mẫu
  const [shifts, setShifts] = useState(() => 
    getInitialData('shifts', [
      { id: 1, name: 'Ca Hành Chính', start: '08:00', end: '17:00' }
    ])
  );

  // 2. DANH SÁCH NHÂN SỰ
  // Lưu ý: Dữ liệu nhân sự sẽ cần có thêm trường shiftId
  const [staffList, setStaffList] = useState(() => 
    getInitialData('staffList', [
      { id: 1, username: 'nv1', password: '123', name: 'Nguyễn Văn A', role: 'staff', shiftId: '1' }
    ])
  );

  // 3. CÁC DỮ LIỆU KHÁC
  const [tasks, setTasks] = useState(() => getInitialData('tasks', []));
  const [attendanceLogs, setAttendanceLogs] = useState(() => getInitialData('attendanceLogs', []));
  const [facilityLogs, setFacilityLogs] = useState(() => getInitialData('facilityLogs', []));

  // --- TỰ ĐỘNG LƯU (AUTO SAVE) ---
  useEffect(() => { localStorage.setItem('shifts', JSON.stringify(shifts)); }, [shifts]);
  useEffect(() => { localStorage.setItem('staffList', JSON.stringify(staffList)); }, [staffList]);
  useEffect(() => { localStorage.setItem('tasks', JSON.stringify(tasks)); }, [tasks]);
  useEffect(() => { localStorage.setItem('attendanceLogs', JSON.stringify(attendanceLogs)); }, [attendanceLogs]);
  useEffect(() => { localStorage.setItem('facilityLogs', JSON.stringify(facilityLogs)); }, [facilityLogs]);

  // --- LOGIC CA LÀM VIỆC ---
  const addShift = (shift) => setShifts([...shifts, { ...shift, id: Date.now() }]);
  
  const deleteShift = (id) => {
    // Logic phụ: Có thể kiểm tra xem có nhân viên nào đang dùng ca này không trước khi xóa (tùy chọn)
    setShifts(shifts.filter(s => s.id !== id));
  };

  // --- LOGIC NHÂN SỰ ---
  const addStaff = (s) => setStaffList([...staffList, { ...s, id: Date.now() }]);
  
  const deleteStaff = (id) => {
    setStaffList(staffList.filter(staff => staff.id !== id));
  };

  const updatePassword = (id, newPassword) => {
    setStaffList(staffList.map(staff => 
      staff.id === id ? { ...staff, password: newPassword } : staff
    ));
  };

  // --- LOGIC TASK & LOGS ---
  const addTask = (t) => setTasks([...tasks, { ...t, id: Date.now(), progress: 0, reason: '' }]);

  const updateTaskProgress = (id, p, reason = '') => 
    setTasks(tasks.map(t => t.id === id ? { ...t, progress: p, reason: reason } : t));

  const addAttendance = (log) => setAttendanceLogs([...attendanceLogs, log]);
  
  const addFacilityLog = (log) => setFacilityLogs([...facilityLogs, log]);

  return (
    <DataContext.Provider value={{ 
      shifts, addShift, deleteShift, // Export logic Ca làm việc
      staffList, addStaff, deleteStaff, updatePassword,
      tasks, addTask, updateTaskProgress, 
      attendanceLogs, addAttendance, 
      facilityLogs, addFacilityLog 
    }}>
      {children}
    </DataContext.Provider>
  );
};

export const useData = () => useContext(DataContext);
